const gptRaw = $input.first().json.message?.content || $input.first().json.text || '{}';
let analysis = {};
try {
  const clean = gptRaw.replace(/```json|```/g, '').trim();
  analysis = JSON.parse(clean);
} catch(e) {
  analysis = { is_lead: false, call_tier: 'Standard', lead_score: 0 };
}

const clientData = $('Parse Client Data').item.json;
const callData   = $('Extract Call Data').item.json;

const durationMs = (callData.end_timestamp || 0) - (callData.start_timestamp || 0);
const durationSec = Math.round(durationMs / 1000);

return {
  // Call metadata
  call_id:           callData.call_id,
  agent_id:          callData.agent_id,
  from_number:       callData.from_number,
  to_number:         callData.to_number,
  transcript:        callData.transcript,
  duration_seconds:  durationSec,
  call_timestamp:    new Date().toISOString(),

  // Client config
  company_name:         clientData.company_name,
  agent_name:           clientData.agent_name,
  lead_email:           clientData.lead_email,
  lead_phone:           clientData.lead_phone,
  notification_email_2: clientData.notification_email_2,
  notification_email_3: clientData.notification_email_3,
  notification_sms_2:   clientData.notification_sms_2,
  notification_sms_3:   clientData.notification_sms_3,
  twilio_from:          clientData.twilio_from,
  timezone:             clientData.timezone,

  // GPT classification — core
  is_lead:           analysis.is_lead || false,
  call_tier:         analysis.call_tier || 'Standard',
  lead_score:        analysis.lead_score || 0,
  caller_name:       analysis.caller_name || '',
  caller_phone:      analysis.caller_phone || '',
  caller_address:    analysis.caller_address || '',
  service_requested: analysis.service_requested || 'Other',
  summary:           analysis.summary || '',
  urgency:           analysis.urgency || 'Low',
  notes:             analysis.notes || '',

  // GPT classification — new intelligence fields
  job_type:            analysis.job_type || 'Residential',
  vulnerable_occupant: analysis.vulnerable_occupant || false,
  caller_sentiment:    analysis.caller_sentiment || 3
};

const leadData = $('Parse Lead Data').item.json;
const geoResponse = $input.first().json;

// ── GEOCODE ──────────────────────────────────────────────────────────────────
let geocode_status = 'not_provided', geocode_formatted = '', geocode_lat = null,
    geocode_lng = null, geocode_maps_url = '', geocode_confidence = 'low', address_check_html = '';

if (!leadData.caller_address || leadData.caller_address.trim().length < 5) {
  geocode_status = 'not_provided';
  address_check_html = '<span style="color:#718096">— Not provided</span>';
} else if (geoResponse.status === 'OK' && geoResponse.results && geoResponse.results.length > 0) {
  const top = geoResponse.results[0];
  geocode_formatted = top.formatted_address;
  geocode_lat = top.geometry.location.lat;
  geocode_lng = top.geometry.location.lng;
  geocode_maps_url = 'https://maps.google.com/?q=' + encodeURIComponent(geocode_formatted);
  const types = top.types || [];
  if (types.includes('street_address') || types.includes('premise') || types.includes('subpremise')) {
    geocode_status = 'verified'; geocode_confidence = 'high';
    address_check_html = '<span style="color:#38a169;font-weight:600">✅ Verified</span> — ' + geocode_formatted + ' &nbsp;<a href="' + geocode_maps_url + '" style="color:#6C63FF;text-decoration:none;font-weight:600">📍 View Map</a>';
  } else if (types.includes('route') || types.includes('intersection')) {
    geocode_status = 'partial'; geocode_confidence = 'medium';
    address_check_html = '<span style="color:#d69e2e;font-weight:600">⚠️ Partial match</span> — ' + geocode_formatted + ' &nbsp;<a href="' + geocode_maps_url + '" style="color:#6C63FF;text-decoration:none">📍 View Map</a>';
  } else {
    geocode_status = 'unverified'; geocode_confidence = 'low';
    address_check_html = '<span style="color:#e53e3e;font-weight:600">⚠️ Unverified</span> — Closest: ' + geocode_formatted + '. Confirm with caller.';
  }
} else if (geoResponse.status === 'ZERO_RESULTS') {
  geocode_status = 'not_found';
  address_check_html = '<span style="color:#e53e3e;font-weight:600">❌ Not found</span> — Confirm address with caller before dispatching.';
} else {
  geocode_status = 'error';
  address_check_html = '<span style="color:#718096">⚠️ Could not verify — confirm with caller</span>';
}

// ── SCORE BADGE ───────────────────────────────────────────────────────────────
const score = leadData.lead_score || 0;
const scoreColor = score >= 8 ? '#dc2626' : score >= 6 ? '#d97706' : '#718096';
const score_badge = '<span style="background:' + (score >= 8 ? '#fef2f2' : score >= 6 ? '#fffbeb' : '#f9fafb') + ';color:' + scoreColor + ';border:2px solid ' + scoreColor + ';border-radius:20px;padding:3px 12px;font-weight:700;font-size:15px">' + score + '/10</span>';

// ── URGENCY BADGE ─────────────────────────────────────────────────────────────
const urgency = leadData.urgency || 'Medium';
const urgencyColor = urgency === 'Emergency' ? '#dc2626' : urgency === 'High' ? '#d97706' : urgency === 'Medium' ? '#2563eb' : '#718096';
const urgency_badge = '<span style="color:' + urgencyColor + ';font-weight:600">' + urgency + '</span>';

// ── TIER BADGE ────────────────────────────────────────────────────────────────
const callTier = leadData.call_tier || 'Standard';
const tierMap = {
  'Emergency': { bg: '#dc2626', label: '🚨 EMERGENCY — Transfer Attempted' },
  'Urgent':    { bg: '#d97706', label: '⚡ URGENT — Respond Within 1 Hour' },
  'Standard':  { bg: '#6C63FF', label: '📋 STANDARD — Business Hours' }
};
const tc = tierMap[callTier] || tierMap['Standard'];
const tier_badge = '<span style="background:' + tc.bg + ';color:#ffffff;padding:5px 14px;border-radius:20px;font-size:12px;font-weight:700;font-family:Helvetica,Arial,sans-serif">' + tc.label + '</span>';

// ── JOB TYPE BADGE ────────────────────────────────────────────────────────────
const jobType = leadData.job_type || 'Residential';
const jobColor = jobType === 'Commercial' ? '#7c3aed' : jobType === 'Multi-Unit' ? '#0369a1' : '#374151';
const jobBg    = jobType === 'Commercial' ? '#f5f3ff' : jobType === 'Multi-Unit' ? '#e0f2fe' : '#f9fafb';
const job_type_badge = '<span style="background:' + jobBg + ';color:' + jobColor + ';padding:2px 10px;border-radius:12px;font-size:12px;font-weight:600;border:1px solid ' + jobColor + '">' + jobType + '</span>';

// ── VULNERABILITY FLAG ────────────────────────────────────────────────────────
const vulnerable = leadData.vulnerable_occupant || false;
const vulnerability_flag = vulnerable
  ? '<span style="background:#fef2f2;color:#dc2626;padding:2px 10px;border-radius:12px;font-size:12px;font-weight:700;border:1px solid #dc2626">⚠️ VULNERABLE OCCUPANT</span>'
  : '';

// ── SENTIMENT INDICATOR ───────────────────────────────────────────────────────
const sentiment = leadData.caller_sentiment || 3;
const sentimentLabel = sentiment <= 2 ? '😟 Distressed' : sentiment === 3 ? '😐 Neutral' : '😊 Cooperative';
const sentimentColor = sentiment <= 2 ? '#dc2626' : sentiment === 3 ? '#6b7280' : '#16a34a';

// ── DURATION ──────────────────────────────────────────────────────────────────
const dur = leadData.duration_seconds || 0;
const duration_formatted = dur >= 60 ? Math.floor(dur/60) + 'm ' + (dur%60) + 's' : dur + 's';

// ── SMS TEXT ──────────────────────────────────────────────────────────────────
// Rich SMS with all key flags — keeps it scannable on a phone
const tierEmoji = callTier === 'Emergency' ? '🚨' : callTier === 'Urgent' ? '⚡' : '📋';
const vulnFlag  = vulnerable ? ' ⚠️VULNERABLE' : '';
const repeatFlag = ''; // populated later by repeat caller check
const notifyType = leadData.notify_type || 'lead';
const sms_header = notifyType === 'emergency'
  ? '🚨 EMERGENCY' + vulnFlag
  : notifyType === 'customer_query'
  ? '📞 CUSTOMER QUERY'
  : '🔥 NEW LEAD';
const sms_text = sms_header + ' — ' + leadData.company_name + '\n'
  + '👤 ' + (leadData.caller_name || 'Unknown') + '\n'
  + '📞 ' + (leadData.caller_phone || leadData.from_number || 'N/A') + '\n'
  + '📍 ' + (geocode_status === 'verified' ? geocode_formatted : leadData.caller_address || 'No address') + '\n'
  + '🔧 ' + (leadData.service_requested || 'General') + ' | ' + jobType + '\n'
  + '⭐ Score: ' + score + '/10\n'
  + '📝 ' + (leadData.summary || '').slice(0, 100);

return {
  ...leadData,
  geocode_status, geocode_formatted, geocode_lat, geocode_lng,
  geocode_maps_url, geocode_confidence, address_check_html,
  score_badge, urgency_badge, tier_badge, job_type_badge,
  vulnerability_flag, sentimentLabel, sentimentColor,
  duration_formatted, sms_text, call_tier: callTier
};

const service  = $json.service_requested || '';
const isLead   = $json.is_lead || false;
const callTier = $json.call_tier || 'Standard';

// Completely drop — return [] stops n8n flow entirely
const dropTypes = ['Spam', 'WrongNumber'];
if (dropTypes.includes(service)) {
  return [];
}

// Classify notification type
let notify_type;
if (callTier === 'Emergency') {
  notify_type = 'emergency';          // red email always for emergency
} else if (service === 'ExistingCustomer' || service === 'Complaint') {
  notify_type = 'customer_query';     // amber email
} else if (isLead) {
  notify_type = 'lead';               // purple email
} else {
  notify_type = 'log_only';           // Supabase only, no email
}

return [{ json: { ...($input.first().json), notify_type } }];

// Route and build notification content
const classify = $('Classify Notification').first().json;
const lead = $('Parse Lead Data').first().json;
const geo = $('Geocode: Parse Result').first().json;
const notifyType = classify.notify_type || '';

// Skip spam/wrong number
if (!notifyType || notifyType === 'spam' || notifyType === 'wrong_number') {
  return { _should_notify: false, _reason: 'Spam or wrong number' };
}

// Build email subject
let subject = '';
if (notifyType === 'emergency') {
  subject = `🚨 EMERGENCY — ${lead.company_name}${lead.vulnerable_occupant ? ' ⚠️ VULNERABLE' : ''}`;
} else if (notifyType === 'customer_query') {
  subject = `📞 Customer Query — ${lead.caller_name || 'Unknown'} | ${lead.company_name}`;
} else {
  subject = `🔥 New Lead — ${lead.company_name} | ${geo.call_tier || 'Standard'}`;
}

// Build email HTML (simplified but professional)
const accentColor = notifyType === 'emergency' ? '#dc2626' : notifyType === 'customer_query' ? '#d97706' : '#6C63FF';
const typeLabel = notifyType === 'emergency' ? '🚨 Emergency Alert' : notifyType === 'customer_query' ? 'Customer Query' : '🔥 New Lead';
const dur = geo.duration_formatted || (lead.duration_seconds ? Math.round(lead.duration_seconds / 60) + ' min' : '—');

const emailHtml = `<!DOCTYPE html><html><head><meta charset="utf-8"></head>
<body style="margin:0;padding:0;background:#f3f4f6;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif">
<table width="100%" cellpadding="0" cellspacing="0" bgcolor="#f3f4f6">
<tr><td align="center" style="padding:40px 16px">
<table width="100%" cellpadding="0" cellspacing="0" style="max-width:540px">
<tr><td bgcolor="${accentColor}" style="height:4px;border-radius:8px 8px 0 0">&nbsp;</td></tr>
<tr><td bgcolor="#ffffff" style="border-radius:0 0 12px 12px;padding:32px 40px 28px">
<p style="margin:0 0 4px;font-size:10px;font-weight:600;letter-spacing:2px;text-transform:uppercase;color:${accentColor}">${typeLabel}</p>
<h1 style="margin:0 0 4px;font-size:22px;font-weight:700;color:#111827">${lead.company_name}</h1>
<p style="margin:0 0 20px;font-size:12px;color:#9ca3af">${dur} call · ${lead.call_timestamp || new Date().toLocaleString()}</p>

<table width="100%" cellpadding="0" cellspacing="0" style="margin-bottom:16px">
<tr><td style="padding:8px 0;border-bottom:1px solid #f3f4f6;font-size:12px;color:#6b7280;width:120px">Caller</td>
<td style="padding:8px 0;border-bottom:1px solid #f3f4f6;font-size:14px;color:#111827;font-weight:600">${lead.caller_name || '—'}</td></tr>
<tr><td style="padding:8px 0;border-bottom:1px solid #f3f4f6;font-size:12px;color:#6b7280">Phone</td>
<td style="padding:8px 0;border-bottom:1px solid #f3f4f6;font-size:14px;color:#111827"><a href="tel:${lead.caller_phone || ''}" style="color:#6C63FF;text-decoration:none">${lead.caller_phone || '—'}</a></td></tr>
<tr><td style="padding:8px 0;border-bottom:1px solid #f3f4f6;font-size:12px;color:#6b7280">Service</td>
<td style="padding:8px 0;border-bottom:1px solid #f3f4f6;font-size:14px;color:#111827">${lead.service_requested || '—'}</td></tr>
