<td style="padding:8px 0;border-bottom:1px solid #f3f4f6;font-size:14px;color:#111827">${geo.geocode_formatted || lead.caller_address || '—'}</td></tr>
<tr><td style="padding:8px 0;border-bottom:1px solid #f3f4f6;font-size:12px;color:#6b7280">Lead Score</td>
<td style="padding:8px 0;border-bottom:1px solid #f3f4f6;font-size:14px;color:#111827;font-weight:600">${lead.lead_score || '—'}/10</td></tr>
</table>

<div style="background:#f9fafb;border-radius:8px;padding:12px 16px;margin-bottom:16px">
<p style="margin:0 0 4px;font-size:12px;color:#6b7280;font-weight:600">Summary</p>
<p style="margin:0;font-size:14px;color:#374151;line-height:1.5">${lead.summary || '—'}</p>
</div>

${lead.notes ? `<div style="background:#fffbeb;border-radius:8px;padding:12px 16px;margin-bottom:16px"><p style="margin:0 0 4px;font-size:12px;color:#92400e;font-weight:600">Notes</p><p style="margin:0;font-size:14px;color:#78350f;line-height:1.5">${lead.notes}</p></div>` : ''}

<p style="margin:16px 0 0;font-size:11px;color:#d1d5db;text-align:center">Syntharra AI Receptionist · ${lead.company_name}</p>
</td></tr></table></td></tr></table></body></html>`;

// Build SMS text
const smsText = geo.sms_text || `New ${notifyType === 'emergency' ? 'EMERGENCY' : 'lead'} for ${lead.company_name}: ${lead.caller_name || 'Unknown'}, ${lead.caller_phone || 'no phone'}, ${lead.service_requested || 'service request'}. Score: ${lead.lead_score || '—'}/10`;

return {
  _should_notify: true,
  notification_type: notifyType,
  email_subject: subject,
  email_html: emailHtml,
  sms_text: smsText,
  // Pass through all data
  lead_email: lead.lead_email || '',
  lead_phone: lead.lead_phone || '',
  notification_email_2: lead.notification_email_2 || '',
  notification_email_3: lead.notification_email_3 || '',
  notification_sms_2: lead.notification_sms_2 || '',
  notification_sms_3: lead.notification_sms_3 || '',
  company_name: lead.company_name || '',
  caller_name: lead.caller_name || '',
  call_id: lead.call_id || '',
  summary: lead.summary || ''
};

